/** Utilities */
function altdivide_btc(coin) {
  // return btcprice.signed_change_rate;

  return ((coin.signed_change_rate / btcprice.signed_change_rate)-1.0).toFixed(2)

}

function altdivide_eth(coin) {
  // return btcprice.signed_change_rate;

  return ((coin.signed_change_rate / ethprice.signed_change_rate)-1.0).toFixed(2)

}

function GetCurrency(price) {
  return Number(price).toLocaleString()
}
function GetRatePrefix(change) {
  switch (change) {
    case 'RISE':
      return  '▲'
    default:
      return '▼'
  }
}
function GetColor(change) {
  switch (change) {
    case 'RISE':
      return 'text-red-600'
    case 'FALL':
      return 'text-blue-600'
    default:
      return 'text-gray-900'
  }
}


function GetChangeRate(rate) {
  return (Number(rate)*100).toFixed(2)
}
function getVolume(volume) {
  return numToKorean(Math.floor(volume / 100000000) * 100000000, 'mixed')
  // return numToKorean(volume)
}

